import { createDiagnosticCollector, getLocationContext, navigateProgram } from "@typespec/compiler";
import { createLinterRuleTester, expectDiagnostics, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { dependencyAuthoringRule } from "./dependency-authoring.rule.js";

/**
 * Compile source (ignoring collateral compiler errors) then run the
 * dependency-authoring linter rule and return its diagnostics only.
 * This mirrors what createLinterRuleTester does internally but skips the
 * expectDiagnosticEmpty guard so tests that trigger compiler-level errors
 * (invalid-namespace-prefix, invalid-decorator-context, …) still reach the rule.
 */
async function runRuleDiagnostics(
  runner: Awaited<ReturnType<typeof Tester.createInstance>>,
  code: string,
) {
  await runner.compileAndDiagnose(code);
  const collector = createDiagnosticCollector();
  const ruleId = `@a10n/blueprint-typespec/${dependencyAuthoringRule.name}`;
  const messages = dependencyAuthoringRule.messages as Record<string, any>;
  // Minimal context replicating createLinterRuleContext (from @typespec/compiler internals)
  const context = {
    program: runner.program,
    reportDiagnostic(diag: { messageId?: string; format?: Record<string, string>; target: any }) {
      const msgDef = messages[diag.messageId ?? "default"];
      const messageStr = typeof msgDef === "string" ? msgDef : msgDef(diag.format ?? {});
      const diagnostic = {
        code: ruleId,
        severity: dependencyAuthoringRule.severity,
        message: messageStr,
        target: diag.target,
      };
      const locCtx = getLocationContext(runner.program, diag.target);
      if (locCtx.type === "project") {
        collector.add(diagnostic as any);
      }
    },
  };
  const listener = dependencyAuthoringRule.create(context as any);
  navigateProgram(runner.program, listener);
  if (listener.exit) await listener.exit(runner.program);
  return collector.diagnostics;
}

describe("dependency-authoring rule", () => {
  let ruleTester: LinterRuleTester;
  let runner: Awaited<ReturnType<typeof Tester.createInstance>>;

  beforeEach(async () => {
    runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, dependencyAuthoringRule, "@a10n/blueprint-typespec");
  });

  // ── dep_component_kind ────────────────────────────────────────────────────
  // Note: @component inside @dependency triggers invalid-namespace-prefix from the
  // @component decorator validator (requires Components.<Name> prefix at top level).
  // These checks are forward-looking rules for when this constraint is relaxed.
  // We test the positive case (no @component inside dep = no dep-component-kind).

  describe("dep-component-kind", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T018.T018_01
    it("T018_01: @dependency with no nested @component — no dep-component-kind diagnostic", async () => {
      await ruleTester
        .expect(`
          @dependency(#{
            title: "Anthropic SDK",
            type: DependencyType.Library,
            status: DependencyStatus.Active,
            sources: #[],
          })
          namespace Dependencies.AnthropicSdk {}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T018.T018_02
    it("T018_02: @dependency with nested namespaces (no @component) — no dep-component-kind", async () => {
      await ruleTester
        .expect(`
          @dependency(#{
            title: "Stripe",
            type: DependencyType.Service,
            status: DependencyStatus.Active,
            sources: #[],
          })
          namespace Dependencies.Stripe {
            namespace Components {
              namespace PaymentsService {
                op charge(): void;
              }
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T018.T018_03
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_dependency_authoring:Products.A10nBlueprintEngine.Features.DependencyAuthoring.dep_component_kind:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_feature_invariant_cap:Products.A10nBlueprintEngine.Features.DependencyAuthoring.dep_component_kind:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_dependency_authoring
    it("T018_03: @dependency containing Agent component emits dep-component-kind", async () => {
      const diagnostics = await runRuleDiagnostics(runner, `
          @dependency(#{
            title: "OpenAI",
            type: DependencyType.Library,
            status: DependencyStatus.Active,
            sources: #[],
          })
          namespace Dependencies.OpenAiAgents {
            @component(#{ type: ComponentType.Agent })
            namespace GptAgent {}
          }
        `);
      expectDiagnostics(diagnostics, [{
        code: "@a10n/blueprint-typespec/dependency-authoring",
        message: /only Sdk and Service components are permitted/,
      }]);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T018.T018_04
    it("T018_04: @dependency containing Store component emits dep-component-kind", async () => {
      const diagnostics = await runRuleDiagnostics(runner, `
          @dependency(#{
            title: "PgWire",
            type: DependencyType.Library,
            status: DependencyStatus.Active,
            sources: #[],
          })
          namespace Dependencies.PgWire {
            @component(#{ type: ComponentType.Store })
            namespace PgStore {}
          }
        `);
      expectDiagnostics(diagnostics, [{
        code: "@a10n/blueprint-typespec/dependency-authoring",
        message: /only Sdk and Service components are permitted/,
      }]);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T018.T018_05
    it("T018_05: @dependency containing Ui component emits dep-component-kind", async () => {
      const diagnostics = await runRuleDiagnostics(runner, `
          @dependency(#{
            title: "Analytics Dashboard",
            type: DependencyType.Library,
            status: DependencyStatus.Active,
            sources: #[],
          })
          namespace Dependencies.AnalyticsDashboard {
            @component(#{ type: ComponentType.Ui })
            namespace DashboardUi {}
          }
        `);
      expectDiagnostics(diagnostics, [{
        code: "@a10n/blueprint-typespec/dependency-authoring",
        message: /only Sdk and Service components are permitted/,
      }]);
    });
  });

  // ── dep_uniform_kind ──────────────────────────────────────────────────────

  describe("dep-uniform-kind", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T018.T018_06
    it("T018_06: @dependency with no components — no dep-uniform-kind diagnostic", async () => {
      await ruleTester
        .expect(`
          @dependency(#{
            title: "Lodash",
            type: DependencyType.Library,
            status: DependencyStatus.Active,
            sources: #[],
          })
          namespace Dependencies.LodashLib {}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T018.T018_07
    it("T018_07: @dependency with empty nested namespace — no diagnostic", async () => {
      await ruleTester
        .expect(`
          @dependency(#{
            title: "AWS",
            type: DependencyType.Service,
            status: DependencyStatus.Active,
            sources: #[],
          })
          namespace Dependencies.Aws {
            namespace Services {}
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T018.T018_08
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_dependency_authoring:Products.A10nBlueprintEngine.Features.DependencyAuthoring.dep_uniform_kind:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_feature_invariant_cap:Products.A10nBlueprintEngine.Features.DependencyAuthoring.dep_uniform_kind:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_dependency_authoring
    it("T018_08: @dependency containing both Sdk and Service components emits dep-uniform-kind", async () => {
      const diagnostics = await runRuleDiagnostics(runner, `
          @dependency(#{
            title: "Stripe",
            type: DependencyType.Service,
            status: DependencyStatus.Active,
            sources: #[],
          })
          namespace Dependencies.Stripe {
            @component(#{ type: ComponentType.Sdk })
            namespace StripeNodeSdk {}

            @component(#{ type: ComponentType.Service })
            namespace StripePaymentsService {}
          }
        `);
      expectDiagnostics(diagnostics, [{
        code: "@a10n/blueprint-typespec/dependency-authoring",
        message: /mixes Sdk and Service components/,
      }]);
    });
  });

  // ── dep_no_tests ──────────────────────────────────────────────────────────
  // Note: @testSuite requires a @component ancestor and @testCase requires @testSuite.
  // These decorator validators prevent them from appearing inside @dependency.
  // The rule is forward-looking for when such constraints are relaxed.
  // We test the positive case (clean dependency = no dep-no-tests).

  describe("dep-no-tests", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T018.T018_11
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_dependency_authoring:Products.A10nBlueprintEngine.Features.DependencyAuthoring.dep_no_tests:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_feature_invariant_cap:Products.A10nBlueprintEngine.Features.DependencyAuthoring.dep_no_tests:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_dependency_authoring:Products.A10nBlueprintEngine.Features.DependencyAuthoring.dep_addresses_components:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_feature_invariant_cap:Products.A10nBlueprintEngine.Features.DependencyAuthoring.dep_addresses_components:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_dependency_authoring
    it("T018_11: @dependency with no nested test constructs — no diagnostic", async () => {
      await ruleTester
        .expect(`
          @dependency(#{
            title: "Stripe",
            type: DependencyType.Service,
            status: DependencyStatus.Active,
            sources: #[],
          })
          namespace Dependencies.Stripe {
            namespace Components {
              namespace PaymentsService {
                op charge(): void;
              }
            }
          }
        `)
        .toBeValid();
    });

    it("T018_11b: @dependency with nested namespace without tests — no diagnostic", async () => {
      await ruleTester
        .expect(`
          @dependency(#{
            title: "Anthropic",
            type: DependencyType.Service,
            status: DependencyStatus.Active,
            sources: #[],
          })
          namespace Dependencies.Anthropic {}
        `)
        .toBeValid();
    });

  });
});
